What does this program print?

```cpp
#include <iostream>

class Base { public: virtual ~Base() = default; };
class A : public Base { public: void hello() const { std::cout << "A\n"; } };
class B : public Base { public: void hello() const { std::cout << "B\n"; } };

int main() {
    A a;
    Base* p = &a;
    if (A* pa = dynamic_cast<A*>(p)) { pa->hello(); }
    if (B* pb = dynamic_cast<B*>(p)) { pb->hello(); }
    else { std::cout << "not B\n"; }
}
```
